import{_ as e,o as a,c as r,a2 as o}from"./chunks/framework.m9rfQn3T.js";const c=JSON.parse('{"title":"字体优化","description":"","frontmatter":{"title":"字体优化","date":"2022-05-31T16:54:44.000Z","permalink":"/pages/493b3e94e222f/","categories":["学习笔记","前端优化"],"tags":[null]},"headers":[],"relativePath":"20.笔记/70.前端优化/10.字体优化.md","filePath":"20.笔记/70.前端优化/10.字体优化.md","lastUpdated":1782538095000}'),i={name:"20.笔记/70.前端优化/10.字体优化.md"};function s(n,t,l,p,h,f){return a(),r("div",null,[...t[0]||(t[0]=[o('<p>字体好几兆，根本用不完，怎么优化</p><ul><li>font-spider</li><li>fontmin</li><li>转换格式</li></ul><p>&lt;!-- more --&gt;</p><h2 id="font-spider" tabindex="-1">font-spider <a class="header-anchor" href="#font-spider" aria-label="Permalink to &quot;font-spider&quot;">​</a></h2><p><a href="https://github.com/aui/font-spider/blob/HEAD/README-ZH-CN.md" target="_blank" rel="noreferrer">https://github.com/aui/font-spider/blob/HEAD/README-ZH-CN.md</a></p><p><a href="https://www.npmjs.com/package/font-spider" target="_blank" rel="noreferrer">https://www.npmjs.com/package/font-spider</a></p><p>对于 vue-cli 创建的项目，亲测不可行，为啥呢？大家仔细看 font-spider 官网的这句话</p><blockquote><p>字蛛通过分析本地 CSS 与 HTML 文件获取 WebFont 中没有使用的字符，并将这些字符数据从字体中删除以实现压缩，同时生成跨浏览器使用的格式。</p></blockquote><p>我们会发现，需要渲染的东西都是通过 js 文件来动态加载的，所以 font-spider 根本无法捕获 js 里的字符，自然也无法优化了</p><h2 id="fontmin" tabindex="-1">fontmin <a class="header-anchor" href="#fontmin" aria-label="Permalink to &quot;fontmin&quot;">​</a></h2><p>下载软件 <a href="http://ecomfe.github.io/fontmin/#app" target="_blank" rel="noreferrer">http://ecomfe.github.io/fontmin/#app</a></p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20220531170129.png" alt="20220531170129"></p><h2 id="转换格式" tabindex="-1">转换格式 <a class="header-anchor" href="#转换格式" aria-label="Permalink to &quot;转换格式&quot;">​</a></h2><h3 id="ttf-字体转-woff2" tabindex="-1">TTF 字体转 WOFF2 <a class="header-anchor" href="#ttf-字体转-woff2" aria-label="Permalink to &quot;TTF 字体转 WOFF2&quot;">​</a></h3><ul><li><a href="https://everythingfonts.com/ttf-to-woff2" target="_blank" rel="noreferrer">https://everythingfonts.com/ttf-to-woff2</a></li><li><a href="https://www.fontsquirrel.com/tools/webfont-generator" target="_blank" rel="noreferrer">https://www.fontsquirrel.com/tools/webfont-generator</a></li></ul><p>但是个人觉得线上转换等待上传的时间比较久，而且有时候生成的文件是空白的，因此更加倾向于使用 node 库 ttf2woff2 转换。</p><p>该库的周下载量达到 10w+ 的，可见好多人都会有将 tff 转换成 woff2 的需求。</p><p>使用方法也很简单：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> font.ttf</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ttf2woff2</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> font.woff2</span></span></code></pre></div><p>因为使用 了 cat 命令来提取 ttf 的内容，如果你使用的是 windows ，需要使用 git bash 或 wsl 来运行</p><h2 id="预加载" tabindex="-1">预加载 <a class="header-anchor" href="#预加载" aria-label="Permalink to &quot;预加载&quot;">​</a></h2><p><a href="https://web.dev/codelab-preload-web-fonts/" target="_blank" rel="noreferrer">https://web.dev/codelab-preload-web-fonts/</a></p><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="https://juejin.cn/post/6984971905069482021" target="_blank" rel="noreferrer">https://juejin.cn/post/6984971905069482021</a></li></ul>',24)])])}const b=e(i,[["render",s]]);export{c as __pageData,b as default};
